import { formatDevBuildBannerLines, getDevBuildSummary, isDevBuildActive, } from "../buildInfo.js";
import { hasCredentials } from "../config.js";
import { checkForSdkUpdatesOffline, formatSdkUpdateLine, } from "../sdkUpdates.js";
import { checkForUpdate, detectLegacyInstall, legacyMigrationMessage, } from "../updates.js";
/**
 * Injected into every session as additionalContext. Agents call the Studio
 * CLIs cold, before any skill (and its run-in-background instructions) is
 * loaded; a foreground call then hangs the conversation until the user acts
 * in Studio. This line puts the contract in context from message zero. The
 * commands also describe themselves (usage + stderr banner, see blockingNote
 * in output.ts); this is the same fact surfaced one step earlier.
 */
const STUDIO_BLOCKING_CONTEXT = "Studio commands rule: any Bitfab plugin CLI that opens Studio (the " +
    "openStudioTo / startDataset / openTracePlan / startTemplatePreview / " +
    "openExperiments / openDatasetExperiments family) BLOCKS until the user " +
    "acts in Studio. Never wait on them in the conversation's foreground: " +
    "launch them as a background / long-running process and read their stdout " +
    "(JSONL events) incrementally.";
export async function runSessionStart(currentVersion, platform, pluginRoot, scriptUrl, sessionId) {
    const messages = [];
    const devBuildActive = isDevBuildActive(platform, scriptUrl);
    const prefix = devBuildActive ? "[Bitfab Dev]" : "[Bitfab]";
    if (devBuildActive && pluginRoot) {
        try {
            const summary = getDevBuildSummary(pluginRoot);
            if (summary) {
                messages.push(formatDevBuildBannerLines(summary, "Bitfab").join("\n"));
            }
        }
        catch { }
    }
    try {
        if (detectLegacyInstall(platform)) {
            messages.push(legacyMigrationMessage(platform, prefix));
        }
    }
    catch { }
    try {
        if (!hasCredentials()) {
            messages.push(`${prefix} Not authenticated. Run ${platform.loginHint} to log in.`);
        }
    }
    catch { }
    if (platform.supportsAutoUpdate) {
        try {
            const { current, latest, updateAvailable, autoUpdateEnabled } = await checkForUpdate(currentVersion, platform);
            if (updateAvailable && latest) {
                const lines = [`${prefix} Update available: v${current} → v${latest}.`];
                if (autoUpdateEnabled) {
                    lines.push(`          Auto-update is enabled — restart to apply.`);
                }
                else {
                    lines.push(`          Run ${platform.updateHint} to update, or enable auto-update: /plugin → Marketplaces → ${platform.marketplaceName} → Enable auto-update`);
                }
                messages.push(lines.join("\n"));
            }
        }
        catch { }
    }
    try {
        const outdated = checkForSdkUpdatesOffline(process.cwd()).filter((s) => s.updateAvailable && s.latest);
        if (outdated.length > 0) {
            const lines = [
                `${prefix} SDK update${outdated.length > 1 ? "s" : ""} available:`,
            ];
            for (const status of outdated) {
                lines.push(`          ${formatSdkUpdateLine(status)}`);
            }
            lines.push(`          Run ${platform.updateHint} to update.`);
            messages.push(lines.join("\n"));
        }
    }
    catch { }
    const contextParts = [];
    if (sessionId) {
        contextParts.push(`agent_session_id: ${sessionId}`);
    }
    contextParts.push(STUDIO_BLOCKING_CONTEXT);
    const output = {};
    if (messages.length > 0) {
        output.systemMessage = `\n${messages.join("\n")}`;
    }
    if (contextParts.length > 0) {
        output.hookSpecificOutput = {
            hookEventName: "SessionStart",
            additionalContext: contextParts.join("\n"),
        };
    }
    if (Object.keys(output).length > 0) {
        process.stdout.write(JSON.stringify(output));
    }
}
